import type { ReactNode } from "react";

import { cn } from "@/lib/utils";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@procertus-ui/ui";

export type PanelSectionProps = {
  /** Section heading; omit for a headerless card (body only). */
  title?: ReactNode;
  /** Muted supporting text under the title. */
  description?: ReactNode;
  /** Main body slot (timeline, lists, actions, etc.). */
  children: ReactNode;
  className?: string;
  /** Classes for the inner `CardContent` (e.g. action row layout). */
  contentClassName?: string;
};

function hasRenderableText(node: ReactNode): boolean {
  if (node == null) return false;
  if (typeof node === "string" || typeof node === "number") return String(node).trim().length > 0;
  return true;
}

/**
 * Card section for detail panels and similar surfaces: optional title + description,
 * consistent spacing, and a full-width body slot (`min-w-0` for overflow safety).
 *
 * Scaffolded via `scaffold workspace-ui add-component PanelSection --variant section`, then
 * narrowed to this presentational API (no marketing footer CTAs).
 */
export function PanelSection({
  title,
  description,
  children,
  className,
  contentClassName,
}: PanelSectionProps) {
  const showTitle = hasRenderableText(title);
  const showDescription = hasRenderableText(description);
  const showHeader = showTitle || showDescription;

  return (
    <Card className={cn("w-full min-w-0", className)}>
      {showHeader ? (
        <CardHeader>
          {showTitle ? <CardTitle>{title}</CardTitle> : null}
          {showDescription ? (
            <CardDescription className="whitespace-normal wrap-break-word">
              {description}
            </CardDescription>
          ) : null}
        </CardHeader>
      ) : null}
      <CardContent className={cn("min-w-0", contentClassName)}>{children}</CardContent>
    </Card>
  );
}

